window.tablesDatabase = window.tablesDatabase || [];

window.tablesDatabase.push({
    id: "narrative-encounters",
    title: "Narrative Exploration Encounters",
    description: "Roll a d100 to discover non-combat exploration scenes, environmental features, or plot seeds tailored to your surroundings.",
    type: "narrative-matrix",
    category: "exploration",
    environments: {
        "Wilderness (Non-Combat)": [
            { min: 1, max: 1, result: "You find an assortment of personal possessions in this area. Roll 5 times on the Items table (p.163), ignoring natural results such as rubble, leaves etc. Only things that would have reasonably been possessions." },
            { min: 2, max: 2, result: "A large number of birds have amassed in an area ahead. Enough to make you wonder why they are all there, filling every tree branch, perched on every boulder and available surface..." },
            { min: 3, max: 3, result: "You meet a local hunter setting traps in the area. She has some interesting information to relate regarding things she has seen in her travels." },
            { min: 4, max: 4, result: "A malevolent, treacherous energy lurks in this area. The god of trickery is worming his way into the minds of all. If you have any sidekicks with you, or if there is more than one PC in your party, then have either a sidekick, PC or NPC make a Wisdom saving throw. If they fail, they turn on your main character, attacking them with their most powerful attack. The effect ceases as soon as this sidekick, PC or NPC either takes damage, or has a spell such as remove curse cast on them. You could also play it like this: have your main PC make a Wisdom save, and if they fail, they attack the NPC/sidekick." },
            { min: 5, max: 5, result: "An NPC (roll on NPC tables if you desire, or simply decide their characteristics) catches up with you and begins asking all sorts of questions. “Where are you coming from? Have you any tales to tell? What is your profession?” They come across as very eager and interested. You’re not sure if they have any motives… perhaps they have just been without company for some time." },
            { min: 6, max: 6, result: "You come across a section of forest that has been destroyed. A druid is in the process of casting plant growth on various small plants to re-vegetate the area." },
            { min: 7, max: 7, result: "You come across an abandoned cabin, its door hanging off the hinges. Belongings are scattered everywhere. There are traces of blood to be found, but no creatures in sight." },
            { min: 8, max: 8, result: "You pass a small inn. A wealthy noblewoman, just passing through, has stopped here and is buying everyone drinks. It seems she has had great luck in business recently." },
            { min: 9, max: 9, result: "A local wizard is accepting visitors to his tower - a group of apprentices from a local alchemy school, who have come to hear a lecture from him on the creation of exotic potions." },
            { min: 10, max: 10, result: "A cart passes, being driven by a figure in a hood who does not address you in any way or even look up from the reins. In the back are various cages and crates. Two of them are covered with thick canvasses, and from within you hear a strange, feral barking and yowling. There are creatures of some kind in there, but you don't know exactly what species." },
            { min: 11, max: 11, result: "A group of pilgrims are on a walking journey towards a temple no-one in the party has heard of. They have been walking for some months already, picking up people along the way." },
            { min: 12, max: 12, result: "You see a wanted poster. A notorious criminal is in the area. 10% chance it is someone you know (NPC or even someone in the party)." },
            { min: 13, max: 13, result: "You come across an ancient fortress that has been inhabited by a group of opportunistic humanoids. They are currently practicing combat manoeuvres and preparing for something. You are a little way off and they have not seen you (yet) but it appears preparations are underway for some kind of combat action." },
            { min: 14, max: 14, result: "Environmental structural shift event active. **[SUB_D4_CATACLYSM]** Ominous portents all point towards some cataclysmic event. You don’t know what it is, but in your soul, you feel as if something momentous has just happened or is about to happen." },
            { min: 15, max: 15, result: "Make a DC 16 Wisdom (Perception) check. If unsuccessful, you fail to notice a hidden **[SUB_D6_TRAP]** which you blunder into. Moments later, cultists emerge from the undergrowth and secure you in ropes. They will try to convert you to their beliefs as part of an aggressive recruitment drive! They have already captured a dozen or so people in this way. You will be subject to enchantment spells and may actually succumb to believing their philosophy, at least for a while." },
            { min: 16, max: 16, result: "You see **[1d4]** rangers who look like they are hot on the trial of something or someone. They stop, crouching to the ground and examining signs in the dirt." },
            { min: 17, max: 17, result: "The smell of yeast and hops is heavy in the air. You emerge in a smallish open area where a neatly-kept building stands beside a babbling brook. Dwarves and halflings are hard at work, milling about this building and performing various jobs. A sign on the outside reads “Stoutfolk Brewery.” (Or perhaps you’d rather come up with your own name!)" },
            { min: 18, max: 18, result: "A shooting pain stabs through your head, nay, your very soul! You feel as though someone is trying to control your mind with magic, or targeting you with some kind of psychic attack." },
            { min: 19, max: 19, result: "You come across a merchant who is deep in haggling with a nobleman. The nobleman is demanding that the merchant sell him some rare item the merchant has in their possession, but the merchant is not budging, insisting that it is not for sale. The nobleman is getting rather hot under the collar. What is this item that has them so fired up?" },
            { min: 20, max: 20, result: "You enter an area where a gallows has been erected. A small crowd has gathered to witness the execution of a monk who has been accused of spying on the local authorities for some rival nation or faction." },
            { min: 21, max: 21, result: "A robbery has been foiled! Highwaymen are lying prone and bound at the side of the road, and a group of passengers have disembarked from an ornate-looking carriage and are preparing to dispense some brutal justice to these unfortunate criminals. The carriage driver and a slightly-dishevelled looking nobleman, bearing cudgels, have somehow got the upper hand." },
            { min: 22, max: 22, result: "Something is approaching. You hear **[SUB_D6_APPROACH]**. You will have time to hide and watch them go by with a successful DC 10 Dexterity (Stealth) check." },
            { min: 23, max: 23, result: "You chance upon a network of caves that look like they could have once been inhabited by a tribe of humanoids." },
            { min: 24, max: 24, result: "You come across two carts which have collided badly. One of the carts overturned and spilled its contents across the road, and now the owner of the goods is having a tantrum and demanding the other cart driver pay for the ruined goods. However, as this is happening, their argument is interrupted by a dull roar from something nearby..." },
            { min: 25, max: 25, result: "A ruined hut is here, with its roof partially caved in." },
            { min: 26, max: 30, result: "System Vector Shift active. **[SUB_D4_CHALLENGE_26]**" },
            { min: 31, max: 31, result: "A piece of parchment is stuck into a tree with a dagger. The parchment is scrawled with messy writing that looks like it was written by a child. It reads: “You are entering the republic of the Forsaken Ones. All who wander in here without proper consent are trespassing and will be dealt with harshly.”" },
            { min: 32, max: 32, result: "You come across an ancient cemetery. All the gravestones are neglected bar one which has had the weeds cleared from around it and fresh flowers placed before it." },
            { min: 33, max: 33, result: "Perched on the edge of a cliff overlooking a small lake, a dilapidated castle, its walls crumbling in places, lies ahead." },
            { min: 34, max: 34, result: "A patrol from a nearby town is halted by the road, their cart having gotten stuck in a muddy rut. They impolitely demand that you assist them in getting the stuck vehicle free. “As a citizen of this realm, it is your civic duty to assist us!”" },
            { min: 35, max: 35, result: "A rustle in some bushes ahead and some easily overheard conversation gives away the position of some juvenile criminals (from a nearby village/town?) planning to ambush a passing cart." },
            { min: 36, max: 36, result: "You come to the top of a gully, thick with vegetation. The sound of drums drifts up to you and smoke from numerous fires rises in plumes above the forest canopy below. Every now and then you hear chanting, different songs, sometimes a dozen or so voices joined as one." },
            { min: 37, max: 37, result: "Making your way through a patch of dense undergrowth, you find a concealed tomb, covered in vines and creepers. Nature has begun reclaiming this forgotten structure, and all signs of who previously inhabited it are gone. Ripping away foliage, you find a stone door." },
            { min: 38, max: 38, result: "You are approaching a grove of trees (or a clearing if you are in a forest) and can see a group of people assembled there. One figure in robes stands before them, and appears to be chanting a litany of some kind. The others repeat the words in a ritualistic fashion." },
            { min: 39, max: 39, result: "Several wizards are here, surrounding a swirling field of energy, attempting to control it. They do not notice your presence, too busy are they with this desperate work! This is some sort of extra-dimensional energy, trying to enter this world..." },
            { min: 40, max: 40, result: "You are approaching a large castle or fortress of some kind. It appears a small military force is arrayed outside its walls, laying siege to the place." },
            { min: 41, max: 41, result: "A band of clerics and monks is tending to what appears to be a huge throng of displaced refugees. Food is being served from huge pots to an endless queue of people. What is their story, how were they forced out of their home, and where will they go from here?" },
            { min: 42, max: 42, result: "High above you see a flying craft, either magical or created using some unknown technology, pass overhead. Where is it heading?" },
            { min: 43, max: 43, result: "Suddenly a group of humanoids passes you. Halflings or gnomes, intent on something and all bearing weapons, are marching purposefully towards some unknown destination. Every now and then, one particularly angry one at the head of the party yells “Come on boys, time for some payback eh?” To which the others all roar in approval." },
            { min: 44, max: 44, result: "You are approached by a group of fey creatures. “Please, we need your help, we’re at our wits end! Our village is being attacked!”" },
            { min: 45, max: 45, result: "A patch of large fungi is ahead. These strange growths appear to be dripping with a violet sap. Looking closer, you see that where this sap has landed on the ground, it has killed everything growing there. It appears to be a virulent poison." },
            { min: 46, max: 46, result: "You come across an enchanted glade, an oasis of some kind. Clear blue water falls from above into a serene pond with a sound like the tinkling of crystals, and trees bearing sweet-smelling flowers arc out over the water, occasionally dropping delicate blooms onto the water’s surface. It is almost too beautiful to be believed..." },
            { min: 47, max: 47, result: "A huge boom, like an explosion, comes from somewhere ahead, perhaps a few miles. It is so massive that you feel the vibration through the earth. What is it? A meteor? A volcano? A powerful spell? The only way to find out is to go and investigate." },
            { min: 48, max: 48, result: "A mansion, the estate of some noble who apparently likes to be away from civilisation, lies ahead. The gates to the place are guarded." },
            { min: 49, max: 49, result: "The moon is high in the sky (whether day or night) but does not appear as normal. **[SUB_D4_MOON]**" },
            { min: 50, max: 50, result: "A group of soldiers and nobles are supervising a book burning." },
            { min: 51, max: 55, result: "System Vector Shift active. **[SUB_D4_BOON_51]**" },
            { min: 56, max: 56, result: "You enter a copse of trees. Then, in the midst of this small, dense wood, you come across several carved symbols of various gods, some festooned with cobwebs, others kept clean and orderly with fresh offerings before them." },
            { min: 57, max: 57, result: "You come across a travelling salesman who deals exclusively in exotic beasts that he keeps in cages. His cart is loaded with them! Perhaps you think him cruel, and no doubt there is an element of cruelty here. But more worrying is the fact that he has gathered all these strange animals together in one place. What would happen if one or more of them were to somehow get free?" },
            { min: 58, max: 58, result: "“Friend!” a voice addresses you from somewhere. “Want to make some money? I need a hand with something. I promise it will be worth your while...” This ragged-looking individual has a story to tell. Use random keywords or event meaning tables (or both) to determine what work he is proposing." },
            { min: 59, max: 59, result: "A pair of warriors, utterly spent and bloodied, lie panting after a ferocious duel. They appear to have been fighting each other all day but are too evenly matched, and neither can get the upper hand. Perhaps you can mediate in this situation. But first, you’ll need to understand their dispute. Keywords!" },
            { min: 60, max: 60, result: "A wide river is ahead, and a large band of workers (probably from a nearby settlement) are creating a dam wall." },
            { min: 61, max: 61, result: "A garishly-coloured bird alights in a nearby tree and regards you with a gaze that is distinctly un-birdlike. “Hmm,” it says, looking you up and down. “Intrigued.”" },
            { min: 62, max: 62, result: "You arrive at a rope bridge which extends over a narrow but deep canyon. However, you are hesitant. The rope looks old and frayed, and you are unsure if it will hold." },
            { min: 63, max: 63, result: "A lone figure is slumped against a tree sobbing. “My master is dead,” they sob." },
            { min: 64, max: 64, result: "You reach the top of a low cliff where you are looking down into what appears to be a quarry. Several ogres are here, bearing whips and other weapons, and are putting a variety of humanoids to work, using them as slaves to mine this area." },
            { min: 65, max: 65, result: "You hear a chorus of soft, melodious voices calling to you from nearby, beckoning you to come closer. The words are almost formed as a song." },
            { min: 66, max: 66, result: "You meet an adventurer, on their way to explore a famed local ruins. Roll on NPC tables (or choose a random, level-appropriate sidekick) and generate a dungeon-based quest using either Chapter 7 of TSAT 1 or any of the quest generation tools in this book. If you wish to pursue this thread, you must take this NPC with you as they are the one who is on this quest. You are accompanying them." },
            { min: 67, max: 67, result: "The foliage suddenly becomes lush and thick in this area. It is a little out of place, and seems to have sprung up unnaturally, as if the result of some kind of natural magic." },
            { min: 68, max: 68, result: "You pass a cave in a low cliff. Someone has fitted a door over the entrance. Has it been turned into a dwelling of some sort? Or, perhaps they merely wanted to restrict entrance." },
            { min: 69, max: 69, result: "You pass rocks that have strange markings on them, that look to be from the earliest humanoid civilization that populated these lands. A DC 14 History check will enable you to determine their basic meaning. Otherwise, who knows what they speak of..." },
            { min: 70, max: 70, result: "A storm approaches from the **[SUB_D4_HORIZON_70]** horizon. You fancy you can see the shapes of various creatures within it. Ominous, dark grey and laced with lightning, it is approaching fast!" },
            { min: 71, max: 71, result: "The sound of fighting nearby, the vibration of heavy footfalls felt through the ground - it seems like two huge creatures of some description are going to it, fighting to the death!" },
            { min: 72, max: 72, result: "A disembodied voice speaks to you directly. Roll on event meaning tables or keywords list to discover what this supernatural voice says to you." },
            { min: 73, max: 73, result: "An absolutely vile smell reaches your nostrils, coming from the **[SUB_D4_HORIZON_73]** horizon. It smells specifically like **[SUB_D4_ODOR_73]**." },
            { min: 74, max: 74, result: "As you watch, you see something shimmer into view, as if teleported from somewhere else. What is it that you see? **[SUB_D10_TELEPORT_74]**" },
            { min: 75, max: 75, result: "Ancient, ruined fortifications lie ahead, although what is behind them is anyone’s guess." },
            { min: 76, max: 80, result: "System Vector Shift active. **[SUB_D4_BANE_76]**" },
            { min: 81, max: 81, result: "A marked change in elevation is causing the land to slope upwards towards a plateau. Several tracks wind their way towards the summit of this elevation, which should afford a good view of the surrounding terrain." },
            { min: 82, max: 82, result: "A travelling apothecary is offering strange herbal remedies with a variety of outlandish effects. Use keywords to determine the nature of these effects." },
            { min: 83, max: 83, result: "The landscape on the side of a gently-sloping hill has been marked with white chalk to resemble the outline of a beast. This land carving may have been here for millennia." },
            { min: 84, max: 84, result: "Steam is rising from a hot springs ahead. You hear conversation also. (Rolled and discovered **[1d4+1]** NPCs relaxing here, using the NPC tables in TSAT 1)." },
            { min: 85, max: 85, result: "More and more, you notice that the wildlife in this area - birds, deer, insects, small creatures of all descriptions - appear to have been magically altered. At first it starts with differences in colouration, but then progresses to mismatched body parts and then totally hybrid creatures. What is causing this anomaly?" },
            { min: 86, max: 86, result: "You reach a low hill - or is it a structure of some kind - which appears to be entirely formed of **[SUB_D4_MINERAL_86]**." },
            { min: 87, max: 87, result: "These rocks look strange here, out of place, and not fitting with the geology of the area. Not only that, there is a curious pattern of spirals covering them which you cannot initially see the purpose of." },
            { min: 88, max: 88, result: "A geyser is erupting clouds of poisonous steam into the air. You may want to avoid this area. However, you see activity going on there... are there creatures living here, even subsisting off these fumes?" },
            { min: 89, max: 89, result: "A patrol from a nearby town is set up here in a roadside booth. Several carts are pulled up and are being inspected for stolen or smuggled goods and contraband." },
            { min: 90, max: 90, result: "You meet a lone NPC on your route. They are a bit confused and keep repeating the same phrase over and over again. “It must never be allowed to happen. It must never be allowed to happen.” Over and over." },
            { min: 91, max: 91, result: "Overhead, you see some sort of astronomical portent. **[SUB_D4_PORTENT_91]** The scriptures/prophecies of old spoke of this, and what it signified..." },
            { min: 92, max: 92, result: "Ahead, you see what appears to be a large walled garden of some kind. A construct stands guard outside it, unmoving. What type of construct is it? **[SUB_D6_CONSTRUCT_92]**." },
            { min: 93, max: 93, result: "A crow flies overhead, and drops a scroll in your path, then turns and departs in an eastern direction. The scroll bears a different message relevant to the quest you are on. Or, if you prefer, the scroll reads as follows: *Adventurer! Heed my call! I am in need of your services. Head east, until you see a great tower, with a sigil marking in its door. That is where I reside. I have a proposition for you.*" },
            { min: 94, max: 94, result: "You come across a large rock. The top half of this rock has been carved into the likeness of a local renowned deity, but the carving is only half-finished and the bottom half of the rock is still in its natural state. It appears this work was abandoned halfway through. Coming closer, you notice that the carver’s tools are still there, scattered on the ground amidst rock chippings." },
            { min: 95, max: 95, result: "You encounter an open-air forge in the middle of this wilderness. There is a hut nearby, and **[1d4]** burly blacksmiths are forging weapons, domestic items, building materials, smelting iron, copper, many different metals, and generally just doing blacksmith stuff." },
            { min: 96, max: 100, result: "Level-appropriate deadly encounter" }
        ],
        "Urban (Non-Combat)": [
            { min: 1, max: 1, result: "You hear rumours of a nomadic cult that has taken up residence in an abandoned building in a deserted part of town. Who knows what they are planning, but there are strange sounds and lights coming from that area." },
            { min: 2, max: 2, result: "A strongman is exhibiting a show of strength at the side of the street, and has drawn a large crowd. However, this burly character looks dejected, exhausted, and the announcer who is narrating his feats appears to be the one in control. Does he have the poor brute magically enslaved? Or is some other form of duress going on here?" },
            { min: 3, max: 3, result: "A guard patrol suddenly runs past you. “To the gates, to the gates!” they are yelling. “We are being attacked!”" },
            { min: 4, max: 4, result: "You pass a market stall. The stallholder is being harassed by someone in a loud voice. “I know you have it, you liar! Give it to me now!”" },
            { min: 5, max: 5, result: "Looking down an alleyway, you can see a figure being set upon by three larger individuals - this definitely does not seem to be a fair fight..." },
            { min: 6, max: 6, result: "Some sort of coloured smoke is billowing out of the windows of a nearby building! Some sort of alchemical chaos perhaps? Or something else..." },
            { min: 7, max: 7, result: "“Accepting all comers!” a huge bugbear yells as he walks down the street, ringing a hand bell. “Tonight, at the Ancient Chalice! Pit fights, only the dirtiest, meanest fighters will survive. 500 gold prize money! We’ll take anyone!”" },
            { min: 8, max: 8, result: "You pass a row of abandoned multi-storey buildings, each one with parchment nailed to the front door. They all read the same: Condemned. Do not enter." },
            { min: 9, max: 9, result: "A large, walled urban garden is here. The sign outside informs you that the garden holds some extremely rare and exotic species." },
            { min: 10, max: 10, result: "An old man telling a story has gathered a large group of children and adults around him, entranced by his narration. It seems he was a former adventurer and has some enthralling tales to tell." },
            { min: 11, max: 11, result: "A streetside merchant is selling baubles, inside which strange colours and scenes are swirling. He tells you that at the right phase of the moon, you can enter one of these baubles as a small pocket dimension, which you can shape to your liking. He’s asking 500gp for each of them. But there is an element of shadiness to this merchant and you perhaps don’t trust him..." },
            { min: 12, max: 12, result: "A local artist is exhibiting works in a gallery. Visitors have reported that his images are so dark and evocative that he must have had some horrific experiences. It’s even said that some descend into madness after viewing these works. Whatever the case, the exhibition seems to be attracting a lot of attention." },
            { min: 13, max: 13, result: "A cart passes by, built of wood and metal, with bars over the windows. Passers-by remark that it is an infamous criminal, finally caught, who is being transported to the town jail. “They never thought they’d catch him,” someone says. “He’s been eluding them for years!”" },
            { min: 14, max: 14, result: "Someone is tolling the alarm bell nearby. Has a fire broken out? Magical chaos? Some sort of catastrophe has occurred that is serious enough to call the town guard over." },
            { min: 15, max: 15, result: "You pass a huge, sprawling graveyard, covering a large area. All the town’s dead are buried here, and it’s said that some tombs connect to a deeper network of catacombs. Currently, however, a crowd is gathered around a freshly-dug grave where a recently-deceased local identity is being interred. This person, you hear someone nearby remark, died in extremely mysterious circumstances. There are many unanswered questions..." },
            { min: 16, max: 16, result: "You pass a magician’s guildhall. It is very active at the moment - a steady stream of mages is coming and going from the door. Inquiring of one of them, you are informed that this guildhall is currently hosting the annual general meeting to discuss the state of magic in the realm." },
            { min: 17, max: 17, result: "A royal procession is about to begin. The Queen/King/Emperor/Empress is due to pass along the street you are on with their entourage very shortly. You see the town guard doing a preliminary sweep of buildings, checking for potential assassins or evil-doers. “Make way!” someone shouts. “Make way for our glorious ruler!” Adults and children alike are beginning to throng either side of the street in anticipation of the regal parade." },
            { min: 18, max: 18, result: "Striking up a conversation with a local, you are told of the old town, a deserted, partially ruined quarter that was recently overrun by monsters. Much slaughter and devastation happened there. “No-one ventures there now,” the local informs you. “It’s said that there are still horrors lurking there, waiting for the foolish to venture in.”" },
            { min: 19, max: 19, result: "You catch a snatch of conversation from two passing locals. “I overheard them talking about it in The Gobbling Gander. Yes, a heist, planned for tonight! The Guild of Scoundrels has never been so daring as to attempt something like this!”" },
            { min: 20, max: 20, result: "A small temple is having a festival which involves a bizarre tradition. **[SUB_D4_FESTIVAL_20]** After this tradition is observed, it is customary for a high-ranking priest to tell a story about their god or goddess’s mythology." },
            { min: 21, max: 21, result: "You pass a grand building under construction. Teams of dwarven stonemasons are crafting this building, working many intricate details into the masonry. Each of the carvings has a story behind it, as the foreman is only too eager to inform you. This building is going to be **[SUB_D4_BUILDING_21]**" },
            { min: 22, max: 22, result: "You begin seeing a poster issuing a reward for a notorious criminal. The thing is, this criminal bears a striking resemblance to a member of your adventuring party!" },
            { min: 23, max: 23, result: "A duel is about to take place, in the middle of the street / town square / market between two rival mages. By all indications, it’s going to get ugly!" },
            { min: 24, max: 24, result: "There is a commodity shortage in this part of town (e.g., food/water/building supplies). Perhaps the local government has placed restrictions on this area because of perceived unlawful behaviour, but whatever the case, the citizenry is on the brink of rioting." },
            { min: 25, max: 25, result: "Since you’ve been in this town, you’ve noticed quite a few suspicious-looking individuals all sporting the same tattoo. You wonder what it could signify." },
            { min: 26, max: 30, result: "System Vector Shift active. **[SUB_D4_CHALLENGE_26]**" },
            { min: 31, max: 31, result: "A noble passes in a litter carried by servants. “Get out of the way, filthy peasants!” the noble rudely shouts as the litter jostles past." },
            { min: 32, max: 32, result: "You hear that a huge ship has just arrived in port from a foreign land. No-one has ever encountered these peoples before, and they are looking to make contact with locals to learn more about local customs and culture. They also brought some fascinating items with them to trade." },
            { min: 33, max: 33, result: "A violent gang conflict (perhaps between two rival thieves’ guilds or other factions) has spilled out into the streets. It’s open warfare out here, with abductions and assassinations happening in broad daylight." },
            { min: 34, max: 34, result: "From a second-story window, you hear a halfling woman singing a pretty song about an ancient hero and their conquests. The story is very descriptive, and you are perhaps overcome with a desire to know more about this legend." },
            { min: 35, max: 35, result: "A worried-looking novice mage is making their way down the street carrying an armful of scrolls. “Can’t be late!” she is saying to herself. “Mistress will kill me if I’m late! If only I had someone to help me with these scrolls!”" },
            { min: 36, max: 36, result: "You see an agile figure bounding across rooftops, carrying something. From quite a way behind, pursuers are yelling at them to stop." },
            { min: 37, max: 37, result: "An eviction is in progress. You see the town guard forcibly removing a family and their grandfather from their house. A woman is screaming: “This is a disgrace! Do you know who my father is? You have no respect! Wait till the duke hears about this, he’ll have your heads!”" },
            { min: 38, max: 38, result: "There is a crack of thunder and rain begins falling very heavily. Stall holders and other vendors begin packing up, and citizens doing their business about town begin running for cover. It is an absolute downpour. You see a nearby tavern which looks cosy and inviting." },
            { min: 39, max: 39, result: "This area of the town is deserted... every house barred, condemned. Then you see them, piled up in the middle of a square. Bodies. A tolling bell catches your attention. “Bring out yer dead!”" },
            { min: 40, max: 40, result: "You see a man running, looking terrified, clutching a relic of some kind. Then, some distance behind him, a mob of well-armed female priests." },
            { min: 41, max: 41, result: "A desperate-looking half-elf peasant clutching a pitchfork asks you if you’ve seen anyone who looks like him pass by recently. He refuses to explain or give his name." },
            { min: 42, max: 42, result: "A guard checkpoint stops everyone except a noble and his entourage." },
            { min: 43, max: 43, result: "You hear word that a ship’s captain is sitting in a nearby tavern, looking for adventurers to accompany him as protection on his next expedition to the outer islands. The pay is terrible and the food worse, but he promises one thing: it won’t be boring." },
            { min: 44, max: 44, result: "An exhibition is in town featuring artifacts from far-flung countries that most people have never heard of." },
            { min: 45, max: 45, result: "Passing an open doorway, you catch a strange scent, and cannot help but glimpse several drowsy-looking people stumbling between rooms. A female, seated by the door, notices your interest. “Fancy a taste?” she asks. “Go see Delren in the back room, he’ll sort you out.”" },
            { min: 46, max: 46, result: "A warrior stumbles out of an alleyway into the middle of the street, a sword impaling him from front to back. “Stop... him...” he manages to say before collapsing onto his knees. He is alive, but only barely." },
            { min: 47, max: 47, result: "A wizard is casting divination spells at passers-by and then tossing off idle remarks about the person’s future." },
            { min: 48, max: 48, result: "“Be on the lookout,” a small company of guards is announcing loudly as they patrol the streets. “Prisoners escaped from the tower!”" },
            { min: 49, max: 49, result: "You see a poster. The local library is getting overstocked and is having a sale of some of its books. Some old books of redundant maps that no-one uses anymore (as they refer to the ancient kingdom, not the current one) and other potentially interesting but obscure tomes are being sold for a fairly reasonable price (100–300 gp per book, depending on rarity)." },
            { min: 50, max: 50, result: "You spy a large building ahead which is subject to some strange metaphysical anomaly. **[SUB_D4_ANOMALY_50]**" },
            { min: 51, max: 55, result: "System Vector Shift active. **[SUB_D4_BOON_51]**" },
            { min: 56, max: 56, result: "A young woman is passing out wooden tokens for a free drink at a local tavern." },
            { min: 57, max: 57, result: "A boat is passing in a nearby canal. It is **[SUB_D4_BOAT_57]**" },
            { min: 58, max: 58, result: "If you have an NPC or sidekick, they are potentially kidnapped by a group of thugs while you are distracted. You could choose this to happen to your PC instead, or your party could witness a kidnapping." },
            { min: 59, max: 59, result: "You see workers loading a huge shipment into boats, or into carts if your settlement is landlocked. You wonder what this shipment is, where it might be going, what it is, who it’s for and whether they have protection on the journey." },
            { min: 60, max: 60, result: "A section of street has fallen into a sinkhole deep below, taking several houses with it. Who knows why this happened, but it is unlikely that the inhabitants of the houses survived." },
            { min: 61, max: 61, result: "You pass a place of business where many vehicles are parked outside. (These could be any sort of vehicle that fits with the lore of your world, from an oxcart to an airship). They are offering passage to most major settlements in the realm. Fares start at 50 gp." },
            { min: 62, max: 62, result: "The panicked news comes to you through the city grapevine, and people are fleeing to safety as a result. A famous local wizard, finally driven insane through his dabblings in obscure subject areas, is on a rampage through the city, destroying everything in his path. Authorities are unsure how to deal with him." },
            { min: 63, max: 63, result: "A stranger runs quickly past you, dropping a random item in your path. **[SUB_D4_ITEM_63]**" },
            { min: 64, max: 64, result: "The street suddenly goes empty but for one or two people, and in the next moment even they are gone. You are alone... Where did everyone go? Then you hear it..." },
            { min: 65, max: 65, result: "A poster announces the public reading of an obscure and arcane scroll recently discovered by an eminent archaeologist in a forgotten tomb near to the city." },
            { min: 66, max: 66, result: "A huge team of workers is busy fixing this part of town. It turns out that this area of the city houses catacombs which connect to the Underdark, through long networks of twisting passages. Somehow, a purple worm found its way up here and burst through the surface, destroying huge amounts of masonry, businesses, residences, ploughing through several blocks of buildings. The damage was immeasurable and will take months to repair. Also, a small company of men-at-arms is stationed there in case any other nasties come up from below..." },
            { min: 67, max: 67, result: "News comes to you of beggars and homeless being killed by some unknown terror..." },
            { min: 68, max: 68, result: "A creature begins following you. **[SUB_D10_CREATURE_68]**" },
            { min: 69, max: 69, result: "A large government building has a crowd protesting outside of it. They could be from a peoples who have been mistreated by the ruling elite. But this is a situation that you know of and has been going on in the realm for years. Decades, even." },
            { min: 70, max: 70, result: "This part of town bears some interesting ancient hieroglyphs etched on various historical walls. Some of them are in a language that no-one has been able to decipher." },
            { min: 71, max: 71, result: "To their great surprise, one of your PCs sees someone from their old home town. This NPC shares news of their hometown, as well as giving access to some local networks." },
            { min: 72, max: 72, result: "You run into an NPC from a previous adventure. Perhaps they were evil and mended their ways (or perhaps not), but anyway they have some interesting stories to tell." },
            { min: 73, max: 73, result: "You see an artisan sitting outside their workshop, finishing off some incredibly detailed work while an apprentice looks on." },
            { min: 74, max: 74, result: "Two expert swordmasters are duelling it out in a public place. The exhibition has drawn a crowd, but no mistake - this is a fight to the death, as evidenced by the expressions of determination on the faces of the competitors." },
            { min: 75, max: 75, result: "You hear a voice in your head. “Do not be alarmed. I speak to you because I can, and because I have seen you before. I do so through magic, but also because I need your services. Come to me at the Inn of the Three Wands. It is hard to find, but you shall know the way. If you do not wish to, forget I have spoken to you and continue on your way. I shall not bother you again. But I promise you, it will be worth your while.”" },
            { min: 76, max: 80, result: "System Vector Shift active. **[SUB_D4_BANE_76]**" },
            { min: 81, max: 81, result: "You encounter a circus performing in a large plaza. Acrobats, jesters, storytellers, puppeteers, illusionists, all manner of entertainers are here, and many interesting market stalls to boot." },
            { min: 82, max: 82, result: "A trio of interesting-looking individuals - adventurers perhaps - blinks into view right in front of you. “What... where are we?” one of them stammers." },
            { min: 83, max: 83, result: "Two halfling women, one old and one young, are walking past you. “It’s all right mother,” the young one says. “It’s only for a little while. The locket should get us a nice purse of gold, then we can be back under a roof before nightfall.” The older one sobs. “That heartless wretch! Casting us out on the street like stray dogs! That locket belonged to my grandmother!”" },
            { min: 84, max: 84, result: "The local botanic gardens are a fascinating place. There is a section of the garden where the foliage grows exceptionally thick, and some of the plants there are known to be quite dangerous to walk near. The supposed reason is that there is a series of tunnels beneath the gardens, and a powerful relic is hidden under that spot. No-one has ever been able to find the entrance to this alleged dungeon however, and no-one knows if it is a relic that is causing this verdant growth, or some other cause." },
            { min: 85, max: 85, result: "You notice guards stationed on the battlements around the city walls. Asking a passing citizen why they are so vigilant, the citizen replies, “There were rumours that a nearby giant colony was planning an attack... so, naturally, that’s got everyone worried.”" },
            { min: 86, max: 86, result: "You pass a building which bears a plaque: “Alyssa Ibold, Scholar of the Realms. Detailed knowledge on all countries and settlements within the known world. Consultations 10 sp per hour.”" },
            { min: 87, max: 87, result: "If one of your PCs worships a god, they see a festival in progress honouring their god. This might be weird if their god is a rare one, but in that case, this is a rare sighting of public practice of that religion. If it is a major religion, then this is a festival holiday. If this doesn’t fit with your character, reroll." },
            { min: 88, max: 88, result: "Many guards are stationed on street corners, preventing access to several city blocks. “Don’t go in there,” one of them tells you. “Trust me, you don’t want to go in there.”" },
            { min: 89, max: 89, result: "You pass a high wall, overrun with creepers. Reaching the gate of this large compound, you peer in to see a huge, dilapidated building, probably once glorious. A sign on the gate reads Compassionate Asylum for Victims of Mind Magic." },
            { min: 90, max: 90, result: "There is a loud crack, and lightning strikes the ground mere feet away from you, filling the air with a strange, burnt smell. Looking up, you see that it is a clear sky, not a cloud. So where did that come from? Does someone powerful have designs on you?" },
            { min: 91, max: 91, result: "Two friendly old wizards are using mage hand to put on a puppet show for local children. The story, however, seems almost too fantastical to be true, and you find yourself drawn in. Does this outlandish tale come from the wizards’ own experience?" },
            { min: 92, max: 92, result: "A gnarled old streetside merchant, who looks like he’s seen some things in his time, is selling pieces of monster anatomy and items made from said anatomy." },
            { min: 93, max: 93, result: "Some young apprentice mages are being bullied by some young warriors-in-training. A classic jocks vs nerds scenario. As you watch, you see that one of the young mages is quietly forming a spell between his hands... You have to see how this turns out!" },
            { min: 94, max: 94, result: "A cartload of prisoners rumbles past. You see all sorts of faces in there, male and female, human, orc, elf, halfling, but all having the look of professional soldiers. “Heading to the prisoner of war camp, three miles out of town,” a passer-by remarks, noticing your interest. “Enemy soldiers transported back here after the latest conflict. A rebellion which the Empire just stamped out. Why they don’t just put them out of their misery is beyond me.”" },
            { min: 95, max: 95, result: "Camped out on the steps of city hall, a tribe of nomadic warriors has erected tents, including a chief’s tent, has made campfires and are roasting a large dead animal on a spit. The town guard are standing around, hesitant to ask these rugged-looking barbarians to move on. Why have they travelled here, you wonder, so far from their homelands? Do they have some issue with the ruling power?" },
            { min: 96, max: 100, result: "Level-appropriate deadly encounter" }
        ],
        "Dungeon (Non-Combat)": [
            { min: 1, max: 1, result: "You find a stricken individual, slumped against the wall of the room/passage and raving to themselves incoherently. They have obviously been involved in something highly traumatic which has robbed them of their wits." },
            { min: 2, max: 2, result: "This area of the dungeon has fallen into disrepair. The passage ahead looks dangerous, like it could cave in at any moment. You will need to proceed with extreme caution." },
            { min: 3, max: 3, result: "An almighty roar fills the passages, echoing around you. It seems to be coming from **[SUB_D4_ROAR_3]**." },
            { min: 4, max: 4, result: "A drunk dwarf is staggering down the passage towards you, arm in arm with a similarly drunk halfling. They are regaling each other with outlandish stories of their adventures, and do not initially notice you." },
            { min: 5, max: 5, result: "You find an adventurer’s corpse (roll on NPC tables to discover details). They have an interesting **[SUB_D6_CORPSE_5]** on their person." },
            { min: 6, max: 6, result: "You find a humanoid child, hiding behind a pillar. They do not speak your language and you have no idea what they are doing here." },
            { min: 7, max: 7, result: "Within a room, a floating orb sits atop a plinth. You approach... the orb is translucent, and many colours swirl within it... what do you see?" },
            { min: 8, max: 8, result: "You see what looks like a portal ahead. The air is stale here, however, and the walls drip with some foul contagion..." },
            { min: 9, max: 9, result: "A magical darkness permeates this area, originating from a point you cannot see. Suddenly, a priest comes into view, smiling and holding forth a holy symbol. “Ah!” he cries. “You’ve come, at last!”" },
            { min: 10, max: 10, result: "You discover a sinkhole in the floor of the passage. Peering down, you see several levels of dungeon passages below you, but the sinkhole (natural?) descends out of sight." },
            { min: 11, max: 11, result: "There is a celebration going on somewhere nearby... the sound of goblets being clinked, wine being poured, even a band of minstrels... but there is a smell hanging heavy in the air... the smell of rotting flesh. Of death... or undeath?" },
            { min: 12, max: 12, result: "A notice is tacked onto a wall. “The fight for the prize begins soon. The victor will claim the symbol of our deity! You will be witness to a great contest...”" },
            { min: 13, max: 13, result: "You come across a creature, which has been wounded. Roll a d8 to find out what type of wounded creature you have come across: **[SUB_D8_CREATURE_13]**. It is not combative. Perhaps an intelligent creature capable of communication might negotiate with you if you can help to heal it. However, do so with care!" },
            { min: 14, max: 14, result: "Huge fungi grow in this area, standing as tall as an ogre! Moving through, you must be careful not to bump them or they will release spores. Make a DC 13 Dexterity (Stealth) check. If you fail, roll three times on the Keywords table (p.167) to discover the nature of the effect the spores have on you." },
            { min: 15, max: 15, result: "A sprite, or some sort of small creature, is down the end of a passageway, beckoning to you. “This way! Yes, come, follow!”" },
            { min: 16, max: 16, result: "You feel imbued with a heroic spirit. The god of courage has smiled on you, granting you a boon. Roll on the Boon table (p.152)." },
            { min: 17, max: 17, result: "You happen upon an underground settlement of some kind. If this is in an established dungeon, perhaps it is a colony of tiny creatures, or an enclave of hermits. If in caverns, or the Underdark, it could be svirfneblin or duergar or drow perhaps. They are not initially aware of your presence and you have the opportunity of observing from afar until you decide to interact." },
            { min: 18, max: 18, result: "The ground begins to shudder, and dust falls from the roof. Perhaps even a chunk of masonry or two falls to the floor. Is this an earthquake, or some huge creature approaching? Either way, it’s seismic." },
            { min: 19, max: 19, result: "You meet a friendly NPC who immediately engages you in conversation. However, they are accompanied by a powerful stench which almost has you gagging. Make a DC 12 Constitution saving throw. If you fail, you are violently ill." },
            { min: 20, max: 20, result: "An adventuring party is ahead, you think. You can hear conversation, several different voices, and they speak in a mixture of Common, Dwarvish and Elvish." },
            { min: 21, max: 21, result: "Small alcoves in either wall house icons to a range of deities you have never seen before. The workmanship looks ancient." },
            { min: 22, max: 22, result: "Within a room, atop a table, you find a fascinating object: an intricately crafted miniature version of a dungeon. This dungeon? Who crafted this and for what purpose?" },
            { min: 23, max: 23, result: "Rows of sarcophagi line either side of this room. Their plaques bear fascinating, and very old inscriptions." },
            { min: 24, max: 24, result: "You stop in your tracks. Ahead (in a room or passage, generate next bit of the dungeon to find out what) you see a mage of some kind deep in the performance of a ritual. But you have no way of knowing their nature, or the nature of the ritual." },
            { min: 25, max: 25, result: "The sound of rushing water comes from nearby. An underground river?" },
            { min: 26, max: 30, result: "System Vector Shift active. **[SUB_D4_CHALLENGE_26]**" },
            { min: 31, max: 31, result: "A trio of gnome artificers are here, hard at work studying some phenomenon, device, construct or other thing. They are escorted by two hulking mercenary warriors. A scientific expedition, it would seem. Stealth roll, DC 14, to see if you are noticed, initially." },
            { min: 32, max: 32, result: "A noxious, yellowish slime covers the walls and floor here. Moving through is going to require agility, and who knows what the effect could be if any of the stuff lands on you... (Use keywords to determine)" },
            { min: 33, max: 33, result: "A small humanoid runs past and tosses an item into your hands. It is a **[SUB_D6_ITEM_33]**. They are gone before you can respond, calling these words back over their shoulder. “Your problem now!” Is something pursuing them? Or have they just offloaded a potentially cursed item on you?" },
            { min: 34, max: 34, result: "There is a lot of noise and hubbub coming from ahead. The clank of steel-shod boots, the shouting of commands. You appear to be approaching a barracks of some kind, and it sounds like they are mobilising for battle!" },
            { min: 35, max: 35, result: "You find a room filled with cages. 1d6 of these cages have captives inside them. You find any combination of the following: **[SUB_D20_CAPTIVE_35]**." },
            { min: 36, max: 36, result: "Ahead, you see the passage seemingly dissolve into nothingness. A void opens up before you. Where a passage was before, now is a swirling, nondescript energy... a portal of some kind? You are hesitant to continue, but also intrigued... Should you back away and try another path, or throw yourself into this strange energy and see where it leads you?" },
            { min: 37, max: 37, result: "At the side of the passage, a beautiful little font, ornately crafted with figures of benevolent, childlike gods, receives silvery water into its stone basin. It radiates a soft, healing energy. Drinking from this font will restore 4d4+8 hp to your character, but you can gain this benefit only once." },
            { min: 38, max: 38, result: "A magical darkness descends. And in this darkness, a voice starts whispering to you, about something from your past that no-one could possibly know about. When the darkness finally lifts, no-one is there... Is someone playing mind games with you, or are you going insane?" },
            { min: 39, max: 39, result: "If you have an NPC with you, they begin acting strangely... as if this place is getting to them, affecting them in some way." },
            { min: 40, max: 40, result: "An offensive smell reaches your nostrils... You come across a pit where all sorts of refuse have been dumped. There must be a humanoid settlement nearby that has seen fit to fill this area with their trash, with no consideration for the other inhabitants of this dungeon. Or, perhaps this is ancient refuse, left here by a group of creatures who have since departed. Either way, it smells utterly repulsive, and you suspect some foul rot-dweller may be lurking in there..." },
            { min: 41, max: 41, result: "You find a collection of items in a bag which you are trying hard to make sense of. Roll five times on the Items table (p.163). Who did this belong to?" },
            { min: 42, max: 42, result: "Rounding a corner, you see a door hanging off its hinges, and a procession of creatures running in and out of a room carrying various looted items. A stash of some kind has been discovered, and it is a free-for-all. The stash consists of one of the following items: **[SUB_D10_STASH_42]**." },
            { min: 43, max: 43, result: "A fresh smell comes to you, as if there was an opening to the outside somewhere near, a vent of fresh air. Then, you round a corner, and see a tree, somehow magically growing in the middle of a widened section of passage. It is suffused with magical light, as if suspended in a bubble, and sits in the middle of a richly-carved dark stone circle which contains the soil it grows in." },
            { min: 44, max: 44, result: "Whoever your quarry is that you are stalking, the reason you entered this dungeon, you find a valuable clue relating to them. You receive this information in one of the following forms: **[SUB_D6_CLUE_44]**." },
            { min: 45, max: 45, result: "A small pebble hits you on the back of the head. Turning around, you cannot see who threw it." },
            { min: 46, max: 46, result: "Entering a natural cavern, you happen upon a pile of gore and dead bodies. This looks like the food stash of some creature, but the smell coming off it is horrific. What lurks nearby?" },
            { min: 47, max: 47, result: "Strange runes glow with an arcane energy, painted on the floor in this area. Make a DC 18 Intelligence (Arcana) or Intelligence (Wisdom) check. If successful, you have seen these runes somewhere before and know something of their meaning." },
            { min: 48, max: 48, result: "A statue in the middle of this area looms high over you. Then, it opens its mouth and speaks to you! Roll on a keywords table or whatever tool you deem appropriate to determine its message." },
            { min: 49, max: 49, result: "An abyss runs across the passageway, dropping down out of sight. Looking down, you see the entrances to various other tunnels, as if peering down through the middle of a colony of insects. The only way across this expanse is a series of floating discs..." },
            { min: 50, max: 50, result: "Entering a chamber, you see a machine or contraption of some sort at its centre, whirring and clicking away. What is this device and what is its purpose?" },
            { min: 51, max: 55, result: "System Vector Shift active. **[SUB_D4_BOON_51]**" },
            { min: 56, max: 56, result: "Blood is pooled through this area, along with arrows, broken weapons, broken crates and other detritus. A pitched battle has gone on here, but you see no bodies... very strange." },
            { min: 57, max: 57, result: "A lone humanoid is wandering the corridors, muttering to themself about how they have been exiled, and how they will get revenge on those that cast them out." },
            { min: 58, max: 58, result: "Water drips from the ceiling above, forming pools here and there. Where is this water coming from... and is it indeed water at all?" },
            { min: 59, max: 59, result: "You hear the sound of a waterfall from somewhere nearby, and also a mechanical noise of some kind, a machine-like sound... Then, above that, the chatter of voices, although due to the sound of the water you can't make out what language they are speaking. What is going on up ahead?" },
            { min: 60, max: 60, result: "This area contains ancient frescoes, some of them ruined, but some remarkably well-preserved. They reveal important lore about the quest you are on, specifically in relation to important people related to that quest, and their history." },
            { min: 61, max: 61, result: "You find a mirror, a small hand-held mirror on the floor. Picking it up, you see that it appears some creature (monster? NPC?) is trapped inside it. How did they come to be here, and why was this artifact simply left lying on the floor?" },
            { min: 62, max: 62, result: "A lever is in the left wall. There is no indication of what it controls, or that it controls anything at all. Perhaps it is defunct. But there is only one way to find out... **[SUB_D6_LEVER_62]**." },
            { min: 63, max: 63, result: "You suddenly emerge on a mezzanine-type floor overlooking a large chamber below. Something is going on down there. Creatures are congregating, but they haven't seen you yet. **[SUB_D6_MEZZANINE_63]**." },
            { min: 64, max: 64, result: "The relentless rhythmic thud of large drums is vibrating from somewhere distant. Is it coming from underneath you? You can feel the pounding through the floor." },
            { min: 65, max: 65, result: "A broken construct lies wrecked in this area. It has been partially, but not wholly, looted for parts. **[SUB_D6_CONSTRUCT_65]**." },
            { min: 66, max: 66, result: "You enter a chamber which appears to be a wizard's or artificer's laboratory. Plenty of interesting artifacts, and quite a few blueprints and other things as well. Roll a d100. If under 20, you find a common magic item. If under 10, you find an uncommon magic item." },
            { min: 67, max: 67, result: "Several boiling cauldrons are in this area, giving off bizarre fumes." },
            { min: 68, max: 68, result: "You emerge in a chamber which is split into two levels, lower and higher. Two groups of humanoids are battling each other, one on the lower ground and one on the higher ground. Neither have noticed you as yet." },
            { min: 69, max: 69, result: "A strange field of coloured light is ahead, dancing hypnotically. Make a DC 14 Wisdom save or you are entranced by this. Who set up this magical trap, and why?" },
            { min: 70, max: 70, result: "You come across several humanoid (or possibly giant) creatures, rolling around on the floor laughing. Something has amused them, but what? Perhaps this is some magic, and you are in danger of falling under it also..." },
            { min: 71, max: 71, result: "A series of huge pillars line both sides of this corridor, which is good as you can hear a creature of quite some size approaching! Might be time to hide..." },
            { min: 72, max: 72, result: "Make a DC 16 Wisdom (Perception) check. If unsuccessful, you fail to notice a skulk deftly relieving you of wealth. Choose either a random item or 2d100 gp to remove from your inventory. If successful, you catch him in the act, and he immediately flees. Make one opportunity attack and then pursue if you wish, encountering 1 skulk." },
            { min: 73, max: 73, result: "There are shallow channels in the floor here, in an interesting, symmetrical pattern. You can find no clue as to their purpose, but a DC 14 Intelligence (Investigation) check might reveal something. If successful, roll on Keywords table (p.167)." },
            { min: 74, max: 74, result: "A room containing chests full of mundane items. Roll ad20 times on the Items table (p.163), discarding inappropriate results like rubble, broken wood etc. All results should be things that have reasonably belonged to someone at some stage." },
            { min: 75, max: 75, result: "The smell of food cooking comes to you, making your mouth water." },
            { min: 76, max: 80, result: "System Vector Shift active. **[SUB_D4_BANE_76]**" },
            { min: 81, max: 81, result: "A group of creatures is ahead, working on renovating a section of the tunnel. What are they doing, and what are their motivations? **[SUB_D6_RENOVATION_81]**" },
            { min: 82, max: 82, result: "You hear the sound of musical instruments, many playing together, but discordant, and well out-of-tune with each other." },
            { min: 83, max: 83, result: "Within a pool, a flawless gem shimmers." },
            { min: 84, max: 84, result: "A burning energy begins to take hold of everything... flammable objects nearby burst into flame, metal objects like torch sconces and doorknobs begin to glow red hot, and everything is suffused with heat. What creature or curse is causing this?" },
            { min: 85, max: 85, result: "Concealed from prying eyes, you stumble somehow across a small library of rare tomes. What strange volumes do you find in here?" },
            { min: 86, max: 86, result: "Conscription patrol. A band of humanoids is approaching. They are searching for recruits for their army in an upcoming battle against an enemy force. Are you allied with their cause?" },
            { min: 87, max: 87, result: "A haunting moan, as of many tormented voices together, begins to come to you, quietly, on the air. It is impossible to determine the source of this disturbing noise." },
            { min: 88, max: 88, result: "A bridge extends over **[SUB_D4_BRIDGE_88]**." },
            { min: 89, max: 89, result: "In the middle of a room, a pendulum swings from side to side, accompanied by a loud ticking noise. Runes are inscribed around all the walls; every surface is covered with writing in... **[SUB_D6_WRITING_89]**. What is the purpose of this device?" },
            { min: 90, max: 90, result: "An idol on a pedestal speaks to you as you pass. “You have forgotten something of your past, traveller. I know all secrets... do you wish me to tell it to you?” If your PC has wishes, this Idol of Memory will reveal a hidden fact about their past." },
            { min: 91, max: 91, result: "As you progress through this area, a succession of ghostly apparitions appear on either side of you, telling you to turn back, that you are entering an area of ancient evil." },
            { min: 92, max: 92, result: "A huge, beautifully-crafted fountain depicts a magical beast and a greenish water spouts from its mouth, filling the pool below the fountain. 50% chance this area is inhabited by humanoids." },
            { min: 93, max: 93, result: "A portal, swirling with planar energy, stands in this area. On the steps leading up to it, you see a note held in place by a stone. It reads: “I waited, but you did not come. Now I go to do the deed. Come find me if you have the courage.”" },
            { min: 94, max: 94, result: "A huge cage, like a birdcage, is suspended from the roof in this area. However, several of the bars are bent open as if what was in it has escaped." },
            { min: 95, max: 95, result: "Ahead, a group of humanoids is towing a large cart carrying **[SUB_D6_CART_95]**." },
            { min: 96, max: 100, result: "Level appropriate deadly encounter" }
        ]
    }
});